class Solution {
    public int nextBeautifulNumber(int n) {
        while (true) {
            n++;
            if (isNumericallyBalanced(n)) {
                return n;
            }
        }
    }

    private boolean isNumericallyBalanced(int num) {
        int[] digitCounts = new int[10];
        int temp = num;
        while (temp > 0) {
            digitCounts[temp % 10]++;
            temp /= 10;
        }
        while (num > 0) {
            int digit = num % 10;
            if (digitCounts[digit] != digit) {
                return false;
            }
            num /= 10;
        }
        return true;
    }
}
```
